-- ========================================
-- Resolve branch_name_tmp → branch_id
-- ========================================
UPDATE receivables r SET r.branch_id = (SELECT b.id FROM branches b WHERE b.name = r.branch_name_tmp LIMIT 1) WHERE r.branch_name_tmp IS NOT NULL;
UPDATE receipts r SET r.branch_id = (SELECT b.id FROM branches b WHERE b.name = r.branch_name_tmp LIMIT 1) WHERE r.branch_name_tmp IS NOT NULL;
UPDATE payable_branches pb SET pb.branch_id = (SELECT b.id FROM branches b WHERE b.name = pb.branch_name_tmp LIMIT 1) WHERE pb.branch_name_tmp IS NOT NULL;
UPDATE payment_out_branches pb SET pb.branch_id = (SELECT b.id FROM branches b WHERE b.name = pb.branch_name_tmp LIMIT 1) WHERE pb.branch_name_tmp IS NOT NULL;

-- Resolve sales_name_tmp → sales_id
UPDATE receivables r SET r.sales_id = (SELECT u.id FROM users u WHERE u.real_name = r.sales_name_tmp LIMIT 1) WHERE r.sales_name_tmp IS NOT NULL;
UPDATE receipts r SET r.sales_id = (SELECT u.id FROM users u WHERE u.real_name = r.sales_name_tmp LIMIT 1) WHERE r.sales_name_tmp IS NOT NULL;

